--
-- Table structure for table `media_managers`
--

CREATE TABLE `media_managers` (
  `id` bigint UNSIGNED NOT NULL,
  `user_id` int DEFAULT NULL,
  `media_file` longtext CHARACTER SET utf8mb3 COLLATE utf8mb3_unicode_ci,
  `media_size` int DEFAULT NULL,
  `media_type` varchar(191) CHARACTER SET utf8mb3 COLLATE utf8mb3_unicode_ci DEFAULT NULL COMMENT 'video / image / pdf / ...',
  `media_name` text CHARACTER SET utf8mb3 COLLATE utf8mb3_unicode_ci,
  `media_extension` varchar(191) CHARACTER SET utf8mb3 COLLATE utf8mb3_unicode_ci DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_unicode_ci;

