(5, 'privacy-policy', 'privacy-policy', '<h1>Privacy Policy</h1>\r\n            <span>Last Updated: [03-03-2025]</span>\r\n            <p>\r\n                SkillTricks (\"we\", \"our\", or \"us\") values your privacy \r\nand is committed to protecting your personal information. This Privacy \r\nPolicy outlines how we collect, use, disclose, and protect your \r\ninformation under the laws of Canada,\r\n                including the Personal Information Protection and \r\nElectronic Documents Act (PIPEDA).\r\n            </p>\r\n            <hr>\r\n            <h3>1. Scope of This Policy</h3>\r\n            <p>This Privacy Policy applies to all visitors, users, and others (\"you\") who access or interact with our website at [website URL].</p>\r\n            <hr>\r\n            <h3>2. Information We Collect</h3>\r\n            <p>We collect the following types of information:</p>\r\n            <h5>A. Personal Information</h5>\r\n            <p>Personal information is any information about an identifiable individual, such as:</p>\r\n            <ul><li>Full Name</li><li>Email Address</li><li>Phone Number</li><li>Company Name</li><li>Mailing Address</li><li>Any information you provide via our contact forms</li></ul>\r\n            <h5>B. Non-Personal Information</h5>\r\n            <p>Non-personal information does not identify you as an individual, such as:</p>\r\n            <ul><li>Browser type and version</li><li>IP Address</li><li>Pages visited and time spent on the site</li><li>Referring website</li></ul>\r\n            <h5>C. Cookies and Tracking Technologies</h5>\r\n            <p>We use cookies and similar technologies to collect \r\ninformation about your interactions with our site. (See our Cookies \r\nPolicy below for details.)</p>\r\n            <hr>\r\n            <h3>3. How We Use Your Information</h3>\r\n            <p>We may use your information for the following purposes:</p>\r\n            <ul><li>To respond to inquiries or service requests.</li><li>To provide and improve our services.</li><li>To communicate with you about updates, promotions, or marketing materials.</li><li>To analyze website usage for improving user experience.</li><li>To comply with legal obligations.</li></ul>\r\n            <hr>\r\n            <h3>4. Sharing Your Information</h3>\r\n            <p>We do not sell your personal information to third parties. However, we may share it under the following circumstances:</p>\r\n            <h5>A. Service Providers</h5>\r\n            <p>We may share your data with third-party providers, such as:</p>\r\n            <ul><li>Email services (e.g., EmailJS, SendGrid)</li></ul>\r\n            <h5>B. Legal Requirements</h5>\r\n            <p>We may disclose your information if required by law or in response to valid legal requests, such as subpoenas or court orders.</p>\r\n            <h5>C. Business Transfers</h5>\r\n            <p>In the event of a merger, acquisition, or sale of assets,\r\n your personal information may be transferred as part of the \r\ntransaction.</p>\r\n            <hr>\r\n            <h3>5. Your Rights Under Canadian Law</h3>\r\n            <p>Under PIPEDA, you have the following rights:</p>\r\n            <ul><li><b>Access and Correction: </b>You can request access to your personal information and correct inaccuracies.</li><li><b>Withdraw Consent: </b>You may withdraw your consent for us to collect, use, or share your data, except where required by law.</li><li><b>Data Portability: </b>Request a copy of your data in a structured, machine-readable format.</li></ul>\r\n            <p>To exercise your rights, contact us at <a href=\"https://login2design.in/htmls/skilltricksinc-new/privacy-policy.html#\">contact@skilltricks.com</a>.</p>\r\n            <hr>\r\n            <h3>6. Data Retention</h3>\r\n            <p>We retain your personal information only for as long as \r\nnecessary to fulfill the purposes outlined in this policy or to comply \r\nwith legal obligations.</p>\r\n            <hr>\r\n            <h3>7. Data Security</h3>\r\n            <p>We implement appropriate physical, technical, and \r\nadministrative safeguards to protect your data from unauthorized access,\r\n loss, or misuse.</p>\r\n            <hr>\r\n            <h3>8. Cross-Border Data Transfers</h3>\r\n            <p>Your data may be transferred to and processed in \r\ncountries outside of Canada. We ensure that appropriate safeguards are \r\nin place to protect your data during such transfers.</p>\r\n            <hr>\r\n            <h3>9. Updates to This Policy</h3>\r\n            <p>We may update this Privacy Policy from time to time. Changes will be posted on this page with a \"Last Updated\" date.</p>\r\n            <hr>\r\n            <h3>10. Contact Us</h3>\r\n            <p>For questions or concerns about this Privacy Policy, please contact us:</p>\r\n            <ul><li><b>Email:</b> <a href=\"mailto:contact@skilltricks.com\" target=\"_blank\">contact@skilltricks.com</a></li><li><b>Phone:</b> <a href=\"tel:(631) 651-8811\">(631) 651-8811</a></li></ul><p><br></p>', 'privacy-policy', NULL, NULL, '2025-04-04 11:13:00', '2025-04-04 11:13:00', NULL, 0, 1, 1, 1),
(6, 'cookies', 'cookies', '<h1>Cookies Policy</h1>\r\n        <span>Last Updated: [03-March-2025]</span>\r\n        <p>This Cookies Policy explains how SkillTricks (\"we\", \"our\", or \"us\") uses cookies and similar technologies.</p>\r\n        <hr>\r\n        <h3>1. What Are Cookies?</h3>\r\n        <p>Cookies are small text files stored on your device when you \r\nvisit a website. They help us understand how you interact with our site \r\nand enhance your experience.</p>\r\n        <hr>\r\n        <h3>2. Types of Cookies We Use</h3>\r\n        <p></p>\r\n        <h5>A. Essential Cookies</h5>\r\n        <p>These cookies are necessary for the website to function properly, such as navigation and access to secure areas.</p>\r\n        <h5>B. Analytics Cookies</h5>\r\n        <p>We use these cookies to understand how visitors use our site and improve functionality.</p>\r\n        <h5>C. Marketing Cookies</h5>\r\n        <p>These cookies are used to track your behavior and display relevant ads.</p>\r\n        <hr>\r\n        <h3>3. Managing Cookies</h3>\r\n        <p>You can control or disable cookies through your browser \r\nsettings. However, disabling certain cookies may limit the functionality\r\n of the website.</p>\r\n        <hr>\r\n        <h3>4. Updates to This Policy</h3>\r\n        <p>We may revise this Cookies Policy from time to time. Check this page periodically for updates.</p><p><br></p>', 'cookies', NULL, NULL, '2025-04-04 11:14:27', '2025-04-04 11:14:27', NULL, 0, 1, 1, 1),
(7, 'terms-of-use', 'terms-of-use', '<h1>Terms of Use</h1>\r\n        <span>Last Updated: [03-March-2025]</span>\r\n        <p>Welcome to SkillTricks! By accessing or using our website, you agree to comply with these Terms of Use.</p>\r\n        <hr>\r\n        <h3>1. Use of the Website</h3>\r\n        <p>You agree to:</p>\r\n        <ul><li>Use the website only for lawful purposes.</li><li>Refrain from engaging in harmful activities, such as hacking or spreading malware.</li></ul>\r\n        <hr>\r\n        <h3>2. Intellectual Property</h3>\r\n        <p>All content on this website, including text, images, and logos, is the property of SkillTricks. Unauthorized use is prohibited.</p>\r\n        <hr>\r\n        <h3>3. User Submissions</h3>\r\n        <p>By submitting information (e.g., via our contact form), you \r\ngrant us permission to use this data for business purposes in accordance\r\n with our Privacy Policy.</p>\r\n        <hr>\r\n        <h3>4. Limitation of Liability</h3>\r\n        <p>SkillTricks is not liable for damages resulting from the use of this website, including:</p>\r\n        <ul><li>Loss of data</li><li>Service interruptions</li><li>Unauthorized access</li></ul>\r\n        <hr>\r\n        <h3>5. Governing Law</h3>\r\n        <p>These Terms are governed by the laws of Canada.</p>\r\n        <hr>\r\n        <h3>6. Contact Us</h3>\r\n        <p>If you have questions about these Terms, contact us at <a href=\"mailto:contact@skilltricks.com\" target=\"_blank\">contact@skilltricks.com</a>.</p><p><br></p>', 'terms-of-use', NULL, NULL, '2025-04-04 11:16:12', '2025-04-04 11:16:12', NULL, 0, 1, 1, 1);

