(132, '17', '[{\"question_id\":\"57\",\"answer\":\"t\"},{\"question_id\":\"58\",\"answer\":\"r\"},{\"question_id\":\"59\",\"answer\":\"r\"},{\"question_id\":\"60\",\"answer\":\"r\"}]', '5', '7', '11', '18', NULL, NULL, 0, 0, '2025-05-29 18:15:54'),
(135, '2', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 0, '2025-05-30 02:14:20'),
