(290, '41', '[{\"question_id\":\"99\",\"answer\":\"Curiosity\\r\\n\\r\\nCraftsmanship\\r\\n\\r\\nCustomer Obsession\\r\\n\\r\\nOwnership\\r\\n(These values guided us when we were a 5-person startup \\u2014 we still hire and promote based on them.)\"},{\"question_id\":\"100\",\"answer\":\"Yes \\u2014 we have a culture deck and onboarding playbook that captures our origin story, core beliefs, and how we made decisions early on. But only a few teams refer to it actively now.\"},{\"question_id\":\"101\",\"answer\":\"Ownership. I want everyone \\u2014 regardless of level \\u2014 to take initiative like they\\u2019re running the company.\"},{\"question_id\":\"102\",\"answer\":\"We\\u2019re hiring 8\\u201310 people per month across Tech, Customer Ops, and Sales. That\\u2019s over 35% growth expected this year.\"},{\"question_id\":\"103\",\"answer\":\"Not officially. Our People & Culture team tries to hold the line, but we don\\u2019t have embedded culture leads within each department.\"}]', '5', '17', '24', '33', NULL, NULL, 0, 0, '2025-11-12 20:14:04'),
