(43, NULL, 'customer', 'Carlos', 'ananyaadivi0611@gmail.com', '6667485216', 1, '114078', NULL, '$2y$10$5IoB7o.GnovNQ7CxyfUNC.hVVwzJR57nj.8x15xlts7Pq8o2tAzR2', 'pmWF7D4X3joEWmnlMPk0R1TAnP3ig4L48mDaNDGBmyIbrHRhUndTOmwuMPtI', NULL, NULL, NULL, 0, NULL, 0, NULL, 1, 1, 0, '2025-07-08 18:59:51', 'Verity Labs', '603-171 Main St N', '11', 'IT Services', '100-500', 'Verity Labs is a SaaS based company', 'yes', '2025-07-08 18:58:20', '2025-07-08 19:03:06', NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(44, NULL, 'customer', 'Jordan Li', 'aksharaadivi0611@gmail.com', '8887546321', 1, '271265', NULL, '$2y$10$9P.flha0dou9cuI0K11TlOMZVBRQvrb7uPIaOEdInpy0hvrHfsGdq', 'uzpTtyNeXF6OIhcdjrcr2WUosiHPJh8vT1Zeo3TMsO6bi1YYdON7o9DIwntC', NULL, NULL, NULL, 0, NULL, 0, NULL, 1, 1, 0, '2025-07-08 19:26:05', 'Verity Labs', '603-171 Main St N', '9', 'IT Services', '100-500', 'Verity is a SaaS based company.', 'yes', '2025-07-08 19:25:51', '2025-07-08 19:26:38', NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(45, NULL, 'customer', 'Alex Jordan', 'alt.no-fo8vwxyi@yopmail.com', '+919999999999', 1, '400843', NULL, '$2y$10$HICytLeakOHBzqRUyLy4xuRh0BjLD2Gyi/B6aRpRfuEM4pxzu2UTK', 'WqdhiSDh0H4M9CIwYF9j7oDSt3FMA1WtSmwgf42AXfl0kePC1cJUeWdIA9MQ', NULL, NULL, NULL, 0, NULL, 0, NULL, 1, 1, 0, '2025-07-22 13:59:05', 'ElevateX Solutions', 'San Francisco, California, USA', '5', 'Software', '100-500', 'Company Overview:\r\nCompany Name: ElevateX Solutions\r\n\r\nTagline: Empowering innovation, accelerating growth.\r\n\r\nVision & Mission:\r\nVision:\r\nTo become a global leader in providing innovative technological solutions that transform businesses, enhance productivity, and foster sustainable growth.\r\n\r\nMission:\r\nDeliver cutting-edge digital products and services tailored specifically for businesses seeking digital transformation through robust project management, resource optimization, and collaborative excellence.\r\n\r\nCompany Details:\r\nGeneral Information:\r\nFounded: 2022\r\n\r\nHeadquarters: San Francisco, California, USA\r\n\r\nIndustry: Technology, Digital Transformation, SaaS\r\n\r\nCompany Type: Privately Held, LLC\r\n\r\nEmployees: 150 (initially)\r\n\r\nAnnual Revenue (Est.): $25M (initial)\r\n\r\nCore Values: Innovation, Collaboration, Integrity, Excellence, Agility, Sustainability\r\n\r\nProducts and Services:\r\nKey Products:\r\nProjectFlow: A comprehensive SaaS tool that integrates task prioritization, timeline adjustments, resource allocation insights, and collaboration analytics.\r\n\r\nAlignX: A cultural alignment and employee sentiment platform providing actionable insights for leadership to enhance team morale and productivity.\r\n\r\nDecisionMap: Goal-decision mapping software designed specifically for project managers, offering clear visibility into task dependencies, critical paths, and risk factors.\r\n\r\nKey Services:\r\nConsulting & Advisory: Digital transformation strategies, Agile implementation, risk management, and team collaboration enhancements.\r\n\r\nCustomized Solutions: Tailored integrations and custom developments leveraging popular project management tools (Jira, Trello, Asana, etc.).\r\n\r\nTraining & Workshops: Comprehensive workshops on Agile, Scrum, Waterfall methodologies, and effective resource and risk management.\r\n\r\nOrganizational Structure:\r\nExecutive Team:\r\nCEO: Alex Jordan\r\n\r\nCOO: Alison Wong\r\n\r\nCTO: Dr. Sofia Chen\r\n\r\nCPO (Chief Product Officer): Priya Malhotra\r\n\r\nVP of Project Management: Marcus Reynolds\r\n\r\nHead of HR & Cultural Alignment: Emily Martinez\r\n\r\nDepartments:\r\nProduct & Technology: Agile development teams (Scrum-based)\r\n\r\nProject Management Office (PMO): Resource allocation and risk management teams\r\n\r\nSales & Marketing: Client relationship management, market analysis, branding\r\n\r\nCustomer Success: Onboarding, customer support, ongoing training\r\n\r\nPeople & Culture: Cultural alignment, HR services, employee wellness initiatives\r\n\r\nKey Markets & Customers:\r\nPrimary markets: North America and Europe (expanding into APAC region).\r\n\r\nTarget Customers:\r\n\r\nMedium to large enterprises aiming for digital transformation.\r\n\r\nIndustries: Technology, Healthcare, Finance, Retail, and Manufacturing.\r\n\r\nCompetitive Advantage:\r\nIntegrated tools explicitly tailored to address project managers\' core pain points—task dependencies, resource allocation, and collaboration gaps.\r\n\r\nAdvanced analytics providing predictive insights and actionable recommendations in real-time.\r\n\r\nEmphasis on aligning corporate culture and employee sentiment to organizational objectives.\r\n\r\nBrand Identity:\r\nLogo:\r\nSymbolizes growth, agility, and technological advancement with modern, streamlined aesthetics.\r\n\r\nColor Scheme:\r\nPrimary Colors: Deep Blue and Silver (representing trust, innovation, and clarity).\r\n\r\nSecondary Colors: Soft Teal and White (representing creativity and simplicity).\r\n\r\nWorkplace Culture & Environment:\r\nCollaborative, inclusive culture fostering innovation and continuous improvement.\r\n\r\nAgile practices: Daily stand-ups, bi-weekly sprint retrospectives, and open feedback mechanisms.\r\n\r\nRegular engagement events to strengthen cross-functional collaboration.\r\n\r\nFuture Roadmap (3-5 years):\r\nExpansion into Artificial Intelligence (AI) and Machine Learning (ML) products.\r\n\r\nGlobal offices in strategic locations (London, Singapore, Sydney).\r\n\r\nStrategic partnerships with leading technology providers and universities for innovation.', 'yes', '2025-07-22 13:58:37', '2025-07-22 14:09:30', NULL, NULL, NULL, NULL, NULL, NULL, NULL);

