(17, '20', '[{\"question_id\":\"40\",\"answer\":\"Expand outreach to underrepresented communities, anonymized screening for select roles, and ERG-driven awareness.\"},{\"question_id\":\"41\",\"answer\":\"Inclusion is tracked through engagement pulse surveys and quarterly review of inclusive behaviors across leadership levels.\"},{\"question_id\":\"42\",\"answer\":\"Use of structured rubrics, bias interrupter prompts during interviews, and training for hiring panels.\"},{\"question_id\":\"43\",\"answer\":\"It\'s a foundational pillar \\u2014 our culture and innovation strategy both rely on a diverse, inclusive workforce.\"}]', '6', '6', '8', '11', 0, 1, 0, '2025-04-21 17:44:01', '2025-05-29 17:49:40'),
